def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.05:
            for k in range(1, 15):
                factor = np.sin(ratio * k * np.pi) + np.cos(k / (ratio + 0.1))
                additive = np.exp(-k * ratio) * (k ** 2.1) * factor
                if k % 4 == 0:
                    additive *= 0.85
                else:
                    additive *= 1.1
                score += additive
            if (int(capacity + item) % 4 == 0) or (int(capacity - item) % 7 == 0):
                score *= 0.75
            if score > 10:
                score /= 3.0
        elif 0.05 <= ratio < 0.2:
            product = 1
            for n in range(1, min(int(capacity) + 5, 25)):
                term = (ratio + n/(n+2)) ** (0.9 + n*0.01)
                product *= term
                if product > 5e6:
                    product = np.log1p(product) * 1.8
                    break
            mod_val = int(product * 7.3) % 400
            score += np.sqrt(ratio * mod_val + 1) * 1.3
            if (int(capacity) % 8 == 0 and int(item * 5) % 4 == 0):
                score += 7.3
            else:
                score -= 1.5
            extra_sum = 0
            for x in range(1, 8):
                fract = ((ratio * x**3 + item) % 1)
                extra_sum += fract * (x ** 2.3)
            score += extra_sum / 7
        elif 0.2 <= ratio <= 0.5:
            for m in range(1, 10):
                inc = (ratio ** (m + 3)) * (m ** 2.9) / ((m + 1.8) ** 0.85)
                score += inc
            remainder = capacity - item
            if remainder < 5:
                score += 15 + remainder * 0.7
            else:
                score -= remainder * 1.1
            if score < -8:
                score = abs(score) * 0.25 + 3
            if int(capacity) % 9 == 0:
                score *= 1.35
            if score > 18:
                score /= 3.5
        elif 0.5 < ratio <= 0.85:
            penalty_base = 0
            for p in range(1, 13):
                val = ((ratio - 0.5) ** p) * (p ** 1.7)
                if val > 70:
                    val = np.log1p(val) * 1.2
                penalty_base += val
                if penalty_base > 80:
                    penalty_base = np.sqrt(penalty_base)
                    break
            score = penalty_base * 14
            if capacity < item * 1.1:
                score += 21
            if (int(capacity * 4) % 9 == 0) and (int(item * 10) % 13 == 0):
                score -= 8
            if score < 0:
                score = score * -1.3 + 7
            if score > 130:
                score = 130
        elif 0.85 < ratio <= 1.2:
            penalty_ext = 0
            diff = ratio - 0.85
            for q in range(1, 14):
                penalty_ext += ((diff) ** q) * (q ** 2.7) / (q + 0.5)
                if penalty_ext > 1400:
                    penalty_ext = np.log1p(penalty_ext) * 50
                    break
            score = penalty_ext * 25
            if capacity < item * 1.4:
                score += 26
            if (int(capacity * 6) % 7 == 0) and (int(item * 11) % 5 == 0):
                score -= 12
            for z in range(1, 8):
                score += ((diff / (z + 0.3)) % 1) * (z * 2.1)
            if score < 0:
                score = abs(score) * 0.6
            if score > 1600:
                score = 1600
        elif 1.2 < ratio <= 1.75:
            super_penalty = 0
            diff = ratio - 1.2
            for r in range(1, 16):
                term = ((diff) ** r) * (r ** 3.2)
                if term > 15000:
                    term = np.sqrt(term) * 1.1
                super_penalty += term
                if super_penalty > 25000:
                    super_penalty = np.log1p(super_penalty) * 40
                    break
            score = super_penalty * 28
            if capacity < item * 2.2:
                score += 35
            if (int(capacity * 15) % 6 == 0) and (int(item * 21) % 8 == 0):
                score -= 18
            for w in range(2, 9):
                score += ((diff / w) % 1) * (w * 2.5)
            if score < 0:
                score = abs(score) * 0.4 + 5
            if score > 2700:
                score = 2700
        else:
            mega_penalty = 0
            diff = ratio - 1.75
            for s in range(1, 20):
                val = ((diff) ** s) * (s ** 3.5)
                if val > 20000:
                    val = np.cbrt(val) * 1.3
                mega_penalty += val
                if mega_penalty > 35000:
                    mega_penalty = np.log1p(mega_penalty) * 50
                    break
            score = mega_penalty * 30
            if capacity < item * 3:
                score += 45
            if (int(capacity * 20) % 9 == 0) and (int(item * 25) % 7 == 0):
                score -= 22
            for u in range(3, 11):
                score += ((diff / u) % 1) * (u * 3)
            if score < 0:
                score = abs(score) * 0.7 + 10
            if score > 4000:
                score = 4000
        if capacity > 300:
            score /= (np.log1p(capacity) + 2.0)
        elif capacity < 7:
            score *= 2.8
        if abs(score) > 2000:
            score = np.sign(score) * 2000
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 0
    else:
        quartiles = np.percentile(finite_priorities, [20, 50, 80])
        top_count = np.sum(finite_priorities > quartiles[2])
        median_val = quartiles[1]
        fill_value = np.max(finite_priorities) * (20 + top_count**1.1) - median_val * 1.5
    priorities[np.isinf(priorities)] = fill_value
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = np.median(finite_priorities) if finite_priorities.size > 0 else 0
    return priorities
